def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            extreme_penalty = 0
            for k in range(1, 5):
                extreme_penalty += (ratio ** (4 * k)) / (k * 3)
            priorities[i] = ratio ** 4 + extreme_penalty
            continue
        if 1 < ratio <= 2:
            base = ratio ** 3
            penalty = 0
            for k in range(1, 4):
                factorial = 1
                for f in range(1, k+1):
                    factorial *= f
                penalty += (ratio ** (2 * k)) / (factorial * (k+1))
            priorities[i] = base + penalty
            continue
        if 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                coeff = (-1)**(j+1)
                score += coeff * (ratio ** j) / (j**2)
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                bonus = 0
                for m in range(1, 6):
                    bonus += ((-1)**m) * (ratio ** (m * 2)) / (m + 2)
                priorities[i] += abs(bonus)
            if 0.4 < ratio < 0.6:
                adjustment = 0
                limit = int(capacity)
                for x in range(1, limit+1):
                    adjustment += np.sin(ratio * x) / (x**1.5)
                priorities[i] += abs(adjustment)
            continue
        if ratio == 0:
            priorities[i] = 0
        else:
            priorities[i] = np.inf
    return priorities
